function genCode(name){return name.trim().toUpperCase().replace(/\s+/g,"").slice(0,3)+Math.floor(10+Math.random()*90);}
function pollock7(sex,age,sf){const s=["chest","axillary","tricep","subscapular","abdominal","suprailiac","thigh"].reduce((a,k)=>a+(+sf[k]||0),0);if(!s)return null;const d=sex==="M"?1.112-0.00043499*s+0.00000055*s*s-0.00028826*age:1.097-0.00046971*s+0.00000056*s*s-0.00012828*age;return((4.95/d-4.50)*100).toFixed(1);}
function pollock3(sex,age,s1,s2,s3){const s=(+s1||0)+(+s2||0)+(+s3||0);if(!s)return null;const d=sex==="M"?1.10938-0.0008267*s+0.0000016*s*s-0.0002574*age:1.0994921-0.0009929*s+0.0000023*s*s-0.0001392*age;return((4.95/d-4.50)*100).toFixed(1);}
function guedes(sex,age,sf){const s=(+sf.subscapular||0)+(+sf.abdominal||0)+(+sf.suprailiac||0);if(!s)return null;const d=sex==="M"?1.17136-0.06706*Math.log(s)-0.0002*age:1.16650-0.07063*Math.log(s)-0.00012*age;return((4.95/d-4.50)*100).toFixed(1);}
function calcBF(method,sex,age,sf){if(method==="pollock7")return pollock7(sex,+age,sf);if(method==="pollock3_M")return pollock3(sex,+age,sf.chest,sf.abdominal,sf.thigh);if(method==="pollock3_F")return pollock3(sex,+age,sf.tricep,sf.suprailiac,sf.thigh);if(method==="guedes")return guedes(sex,+age,sf);return null;}
function bmi(w,h){return h>0?(w/((h/100)**2)).toFixed(1):null;}
