const SESSION_TYPES=["Treino","Avaliação","Retorno","Reposição","Online"];function Avatar({name="?",size=42}){const i=name.trim().split(" ").filter(Boolean).slice(0,2).map(w=>w[0]).join("").toUpperCase()||"?";return <div style={{width:size,height:size,borderRadius:"50%",background:`linear-gradient(135deg,${B.lime},${B.limeD})`,display:"flex",alignItems:"center",justifyContent:"center",fontWeight:900,fontSize:size*.34,color:B.bg,flexShrink:0}}>{i}</div>;}
