function FL({children}){return <div style={{fontSize:11,fontWeight:700,color:B.muted,marginBottom:5,letterSpacing:"0.04em"}}>{children}</div>;}
function TI({label,value,onChange,placeholder,type="text",small,style={}}){return <div style={{marginBottom:small?8:13,...style}}>{label&&<FL>{label}</FL>}<input type={type} value={value??""} onChange={onChange} placeholder={placeholder} style={{width:"100%",background:B.surfaceHigh,border:`1px solid ${B.border}`,borderRadius:9,padding:small?"7px 10px":"11px 13px",color:B.text,fontSize:small?13:14,outline:"none",fontFamily:"inherit"}} onFocus={e=>e.target.style.borderColor=B.lime} onBlur={e=>e.target.style.borderColor=B.border}/></div>;}
function SI({label,value,onChange,options,small}){return <div style={{marginBottom:small?8:13}}>{label&&<FL>{label}</FL>}<select value={value??""} onChange={onChange} style={{width:"100%",background:B.surfaceHigh,border:`1px solid ${B.border}`,borderRadius:9,padding:small?"7px 10px":"11px 13px",color:B.text,fontSize:small?13:14,outline:"none",fontFamily:"inherit",cursor:"pointer"}}>{options.map(o=><option key={o.v} value={o.v}>{o.l}</option>)}</select></div>;}
function Btn({children,onClick,variant="primary",style={},disabled}){const vs={primary:{background:B.lime,color:B.bg},secondary:{background:B.surfaceHigh,color:B.muted,border:`1px solid ${B.border}`},danger:{background:"#7f1d1d",color:"#fca5a5",border:"1px solid #991b1b"},outline:{background:"transparent",color:B.lime,border:`1px solid ${B.lime}`}};return <button onClick={onClick} disabled={disabled} style={{width:"100%",padding:"11px 0",borderRadius:10,border:"none",fontWeight:800,fontSize:13,cursor:disabled?"not-allowed":"pointer",opacity:disabled?0.5:1,fontFamily:"inherit",...vs[variant],...style}}>{children}</button>;}
